class Solution(object):
    def minOperations(self, nums):
        def is_bin_pal(x):
            b = bin(x)[2:]
            return b == b[::-1]

        def cost(x):
            if is_bin_pal(x):
                return 0
            lo, hi = x - 1, x + 1
            while True:
                if lo >= 1 and is_bin_pal(lo):
                    return x - lo
                if is_bin_pal(hi):
                    return hi - x
                lo -= 1
                hi += 1

        return [cost(x) for x in nums]
